function drawTower() { if(isDrawing) return; if(gold < drawCost) return say(`Tower roulette costs ${drawCost}. You need ${drawCost-gold} more supplies.`); const allowedGrades=getRouletteGrades(), previews=Object.values(types).filter(type=>allowedGrades.some(grade=>grade.id===type.grade)); if(!previews.length) return say('No towers are available for the roulette.'); const cost=drawCost; isDrawing=true; gold-=cost; recordStats({draws:1}); ui.rollButton.disabled=true; ui.rollButton.classList.add('rolling'); updateUI(); try { setRouletteTower(previews[Math.floor(Math.random()*previews.length)]); drawSpinTimer=setInterval(()=>{setRouletteTower(previews[Math.floor(Math.random()*previews.length)]);},65); drawTimer=setTimeout(()=>{try { let roll=Math.random()*allowedGrades.reduce((sum,grade)=>sum+getGradeChance(grade),0), grade=allowedGrades[0]; for(const entry of allowedGrades){roll-=getGradeChance(entry);if(roll<=0){grade=entry;break;}} const candidates=previews.filter(type=>type.grade===grade.id); const drawn=candidates[Math.floor(Math.random()*candidates.length)]; if(!drawn) throw new Error('roulette result missing'); setRouletteTower(drawn); inventory[drawn.id].push(1); selected=drawn.id; say(`Tower roulette: ${drawn.name}!`); } catch { gold+=cost; say('Roulette error recovered. Your supplies were refunded.'); } finally { finishRoulette(); updateUI(); } },850); } catch { gold+=cost; finishRoulette(); updateUI(); say('Roulette error recovered. Your supplies were refunded.'); } }

