canvas.addEventListener('click', event => { if(gameOver) return; const {x,y}=eventToWorld(event); if(activeSkill)return useActiveSkill(x,y); const pad=pads.find(p=>distance({x,y},p)<36), selectedType=selected&&types[selected]; if(pad){if(pad.tower) return fusionMode ? fuseWith(pad.tower) : selectTower(pad.tower); if(fusionMode) return say('Fusion needs a matching installed tower.'); return buildAt(pad);} const pathTower=towers.find(t=>t.pathTrap&&distance({x,y},t)<28); if(pathTower) return fusionMode ? fuseWith(pathTower) : selectTower(pathTower); if(fusionMode) return say('Fusion needs a matching installed tower.'); if(selectedType&&selectedType.kind==='thorns') return deployThornsOnPath(x,y); say('Click a glowing hexagonal build zone.'); });
