function hurt(enemy, amount, color) {
  enemy.hp -= amount;
  enemy.hit = .12;
  for(let i=0;i<5;i++) particles.push({x:enemy.x,y:enemy.y,vx:(Math.random()-.5)*90,vy:(Math.random()-.5)*90,life:.35,size:2+Math.random()*3,color});
  if(enemy.hp > 0) return;
  gold += enemy.reward;
  recordStats({kills:1,normalKills:enemy.boss||enemy.elite?0:1,eliteKills:enemy.elite?1:0,bossKills:enemy.boss?1:0,suppliesEarned:enemy.reward});
  particles.push({x:enemy.x,y:enemy.y,vx:0,vy:0,life:.55,size:enemy.r*2.6,color:'#ffe779',burst:true});
  enemies.splice(enemies.indexOf(enemy),1);
  if(enemy.boss){
    const gemGain=1+gemUpgrades.bounty;
    gems+=gemGain;
    baseUpgrades.fortify++;
    lives+=5;
    const rouletteUpgraded=baseUpgrades.roulette<getUpgradeMax('roulette')&&Math.random()<.5;
    if(rouletteUpgraded) baseUpgrades.roulette++;
    persistPermanentProgress();
    say(`${rouletteUpgraded?'BOSS DEFEATED! Roulette Mastery +1.':'BOSS DEFEATED! Roulette Mastery stayed the same.'} +${gemGain} GEM. Permanent keep health LV ${baseUpgrades.fortify} (+${baseUpgrades.fortify*5} starting HP).`);
  }
  updateUI();
}
function applySlow(enemy, duration, factor) { enemy.slow=Math.max(enemy.slow||0,duration); enemy.slowFactor=Math.min(enemy.slowFactor||1,factor); }
function applyDot(enemy, kind, duration, damage) { enemy[kind]=Math.max(enemy[kind]||0,duration); enemy[`${kind}Damage`]=Math.max(enemy[`${kind}Damage`]||0,damage); enemy.statusTick=0; }
function nearbyEnemies(target, radius, count) { return enemies.filter(enemy=>enemy!==target&&distance(enemy,target)<radius).sort((a,b)=>b.progress-a.progress).slice(0,count); }
function applyThornAbility(tower, enemy) { const tier=getGradeTier(tower); if(tower.type.ability==='root') applySlow(enemy,.35+tier*.1,.74-tier*.035); if(tower.type.ability==='freeze') applySlow(enemy,.7+tier*.12,.54-tier*.035); if(tower.type.ability==='poison') applyDot(enemy,'poison',2+tier*.35,getTowerDamage(tower)*(.16+tier*.035)); if(tower.type.ability==='magma') applyDot(enemy,'burn',2.5+tier*.35,getTowerDamage(tower)*(.24+tier*.04)); }
function triggerShotAbility(shot) { const tier=getGradeTier(shot.tower), ability=shot.tower.type.ability, target=shot.target, targetAlive=enemies.includes(target); if(ability==='chain') nearbyEnemies(target,70,1+tier).forEach(enemy=>hurt(enemy,shot.damage*(.42+tier*.035),shot.color)); if(ability==='shock'&&targetAlive) applySlow(target,.45+tier*.12,.7-tier*.035); if(ability==='prism') nearbyEnemies(target,92,1+tier).forEach(enemy=>hurt(enemy,shot.damage*(.48+tier*.035),shot.color)); if(ability==='storm') nearbyEnemies(target,98,2+tier).forEach(enemy=>hurt(enemy,shot.damage*(.5+tier*.035),shot.color)); if(ability==='splash') nearbyEnemies(target,42+tier*10,99).forEach(enemy=>hurt(enemy,shot.damage*(.5+tier*.03),shot.color)); if(ability==='mortar') nearbyEnemies(target,68+tier*12,99).forEach(enemy=>hurt(enemy,shot.damage*(.62+tier*.035),shot.color)); if(ability==='burn'&&targetAlive) applyDot(target,'burn',2+tier*.4,shot.damage*(.22+tier*.04)); if(ability==='flame'){const victims=[target,...nearbyEnemies(target,54+tier*7,3+tier)];victims.filter(enemy=>enemies.includes(enemy)).forEach(enemy=>applyDot(enemy,'burn',2.4+tier*.35,shot.damage*(.28+tier*.035)));} if(ability==='volcano'){const victims=[target,...nearbyEnemies(target,88+tier*12,99)];victims.filter(enemy=>enemies.includes(enemy)).forEach(enemy=>{if(enemy!==target)hurt(enemy,shot.damage*(.72+tier*.035),shot.color);applyDot(enemy,'burn',3+tier*.4,shot.damage*(.3+tier*.04));});} }
function update(dt) {
  if(bossIntro){ bossIntro.time-=dt; if(bossIntro.time<=0)bossIntro=null; return; }
  if(running && spawnQueue.length){ spawnCooldown -= dt; if(spawnCooldown <= 0){ enemies.push(makeEnemy(spawnQueue.shift())); spawnCooldown = .58; } }
  for(const enemy of [...enemies]) { enemy.poison=Math.max(0,(enemy.poison||0)-dt); enemy.burn=Math.max(0,(enemy.burn||0)-dt); enemy.statusTick=(enemy.statusTick||0)-dt; if(enemy.statusTick<=0&&(enemy.poison>0||enemy.burn>0)){enemy.statusTick=.35;const dotDamage=(enemy.poison>0?enemy.poisonDamage:0)+(enemy.burn>0?enemy.burnDamage:0);hurt(enemy,dotDamage*.35,enemy.burn>0?'#ff9d55':'#ae7cff');if(!enemies.includes(enemy))continue;} enemy.progress=Math.max(enemy.spawnProgress,enemy.progress+enemy.speed*dt*(enemy.slow > 0 ? enemy.slowFactor||.62 : 1)); enemy.slow=Math.max(0,enemy.slow-dt); if(!enemy.slow) enemy.slowFactor=1; enemy.hit=Math.max(0,enemy.hit-dt); const pos=pointOnPath(enemy.progress); enemy.x=pos.x; enemy.y=pos.y; enemy.angle=pos.angle; if(enemy.progress >= pathLength){ enemies.splice(enemies.indexOf(enemy),1); lives=Math.max(0,lives-enemy.damage); updateUI(); say(`${enemy.type.name} hit the keep for ${enemy.damage} damage!`); if(lives <= 0){ gameOver=true; running=false; recordStats({deaths:1}); showDeathUpgrades(); } } }
  for(const tower of towers) { tower.cooldown -= dt; tower.pulse=Math.max(0,tower.pulse-dt); const range=getTowerRange(tower), targets=enemies.filter(e=>distance(tower,e)<range); if(!targets.length) continue; const target=targets.reduce((best,e)=>e.progress>best.progress?e:best,targets[0]); tower.angle=Math.atan2(target.y-tower.y,target.x-tower.x); if(tower.type.kind === 'thorns'){ if(tower.cooldown <= 0){ targets.filter(e=>distance(tower,e)<range).forEach(enemy=>{applyThornAbility(tower,enemy);hurt(enemy,getTowerDamage(tower),tower.type.color);}); tower.cooldown=getTowerFireRate(tower); tower.pulse=.25; } } else if(tower.cooldown <= 0){ tower.cooldown=getTowerFireRate(tower); tower.pulse=.15; shots.push({x:tower.x,y:tower.y,target,tower,damage:getTowerDamage(tower),color:tower.type.color,kind:tower.type.kind,speed:tower.type.kind === 'spark' ? 720 : 410}); } }
  for(const shot of [...shots]) { if(!enemies.includes(shot.target)){ shots.splice(shots.indexOf(shot),1); continue; } const dx=shot.target.x-shot.x,dy=shot.target.y-shot.y,d=Math.hypot(dx,dy),move=shot.speed*dt; if(d < move+shot.target.r){ hurt(shot.target,shot.damage,shot.color); triggerShotAbility(shot); shots.splice(shots.indexOf(shot),1); } else { shot.x+=dx/d*move; shot.y+=dy/d*move; } }
  for(const strike of [...airstrikes]) { strike.delay-=dt;if(strike.delay>0)continue;for(const enemy of [...enemies])if(distance(enemy,strike)<=strike.radius)hurt(enemy,strike.damage,'#ffd15f');for(let i=0;i<30;i++){const angle=Math.random()*Math.PI*2,speed=90+Math.random()*210;particles.push({x:strike.x,y:strike.y,vx:Math.cos(angle)*speed,vy:Math.sin(angle)*speed,life:.65+Math.random()*.25,size:4+Math.random()*7,color:i%3?'#ff9c4d':'#fff3a4'});}particles.push({x:strike.x,y:strike.y,vx:0,vy:0,life:.7,size:strike.radius*.9,color:'#ffe779',burst:true});airstrikes.splice(airstrikes.indexOf(strike),1);}
  for(const p of particles){ p.life-=dt; p.x+=p.vx*dt; p.y+=p.vy*dt; p.vx*=.92; p.vy*=.92; } particles=particles.filter(p=>p.life>0);
  if(running && !spawnQueue.length && !enemies.length) endWave();
}

function hex(x,y,r,fill,stroke) { ctx.beginPath(); for(let i=0;i<6;i++){const a=Math.PI/3*i+Math.PI/6,px=x+Math.cos(a)*r,py=y+Math.sin(a)*r; i?ctx.lineTo(px,py):ctx.moveTo(px,py);} ctx.closePath(); ctx.fillStyle=fill; ctx.fill(); if(stroke){ctx.strokeStyle=stroke;ctx.lineWidth=2;ctx.stroke();} }
