  if(tier>=3){ctx.globalAlpha=.38;ctx.lineWidth=2;ctx.setLineDash([5,4]);ctx.rotate(-time*.9);ctx.beginPath();ctx.arc(0,0,35,0,Math.PI*2);ctx.stroke();ctx.setLineDash([]);}
