  if(tier>=3){ctx.globalAlpha=.9;ctx.beginPath();ctx.moveTo(-13,-24);ctx.lineTo(-6,-37);ctx.lineTo(0,-27);ctx.lineTo(7,-39);ctx.lineTo(15,-24);ctx.closePath();ctx.fill();}
