function drawFusionReadyEffect(t) {
  if(!matchingTower(t)) return;
  const time=performance.now()/1000, radius=34+Math.sin(time*5+t.x*.02)*3;
  ctx.save();
  ctx.globalCompositeOperation='lighter';
  ctx.globalAlpha=.2+.12*Math.sin(time*5+t.y*.02);
  ctx.fillStyle='#ffe46e';ctx.beginPath();ctx.arc(0,0,radius,0,Math.PI*2);ctx.fill();
  ctx.globalAlpha=.9;ctx.strokeStyle='#fff18b';ctx.lineWidth=2;ctx.setLineDash([5,4]);ctx.rotate(time*.9);ctx.beginPath();ctx.arc(0,0,radius,0,Math.PI*2);ctx.stroke();ctx.setLineDash([]);
  for(let i=0;i<3;i++){const angle=time*2+i*Math.PI*2/3;ctx.fillStyle='#fff6bb';ctx.beginPath();ctx.arc(Math.cos(angle)*(radius+5),Math.sin(angle)*(radius+5),2.5,0,Math.PI*2);ctx.fill();}
  ctx.restore();
}
function drawEnemy(e) { ctx.save();ctx.translate(e.x,e.y);ctx.rotate(e.angle);ctx.fillStyle=e.hit?'#fff6ce':e.type.body;ctx.fillRect(-e.r,-e.r*.65,e.r*2,e.r*1.3);ctx.fillStyle=e.type.top;ctx.fillRect(-e.r*.65,-e.r*.88,e.r*1.2,e.r*.4);ctx.fillStyle='#2d2028';ctx.fillRect(-e.r*.25,-e.r*.43,e.r*.17,e.r*.16);ctx.fillRect(e.r*.17,-e.r*.43,e.r*.17,e.r*.16);if(e.elite || e.boss){ctx.strokeStyle='#fff0a8';ctx.lineWidth=e.boss?4:2;ctx.strokeRect(-e.r-3,-e.r*.82,e.r*2+6,e.r*1.62);}if(e.boss){ctx.fillStyle='#ffe28a';ctx.font='bold 14px system-ui';ctx.fillText('BOSS',-18,-e.r-11);}ctx.restore();const w=e.boss?92:e.elite?46:30,barY=e.y-e.r-17;ctx.fillStyle='#172b2f';ctx.fillRect(e.x-w/2,barY,w,e.boss?8:5);ctx.fillStyle=e.boss?'#ffcb52':e.elite?'#ffd16d':e.type.top;ctx.fillRect(e.x-w/2,barY,w*Math.max(0,e.hp/e.maxHp),e.boss?8:5);ctx.fillStyle=e.boss?'#ffe28a':e.elite?'#f7e5aa':'#eefbf1';ctx.font=`bold ${e.boss?10:8}px system-ui`;ctx.textAlign='center';ctx.fillText(e.type.name,e.x,barY-15);ctx.fillStyle='#fff4bb';ctx.font='bold 8px system-ui';ctx.fillText(`DMG ${e.damage}`,e.x,barY-5);ctx.textAlign='left'; }
function drawEnemyLevelEffect(e) { const level=e.level||1, power=Math.min(12,level); if(level<=1)return; const radius=e.r*(1.12+power*.025), time=performance.now()/1000;ctx.save();ctx.translate(e.x,e.y);if(level>=2){ctx.globalAlpha=.22+.08*Math.sin(time*4+e.x*.02);ctx.fillStyle=e.elite||e.boss?'#ffd469':'#9be7ff';ctx.beginPath();ctx.arc(0,0,radius+5,0,Math.PI*2);ctx.fill();ctx.globalAlpha=.8;ctx.strokeStyle=e.elite||e.boss?'#ffe49b':'#c6f4ff';ctx.lineWidth=1.5;ctx.beginPath();ctx.arc(0,0,radius,0,Math.PI*2);ctx.stroke();}if(level>=4){ctx.strokeStyle='#d9edf4';ctx.lineWidth=2;ctx.globalAlpha=.75;ctx.strokeRect(-e.r-3,-e.r*.78,e.r*2+6,e.r*1.55);}if(level>=6){ctx.fillStyle='#ff9a58';ctx.globalAlpha=.9;for(let i=0;i<4;i++){const angle=time*1.4+i*Math.PI/2;ctx.beginPath();ctx.moveTo(Math.cos(angle)*(radius-1),Math.sin(angle)*(radius-1));ctx.lineTo(Math.cos(angle)*(radius+10),Math.sin(angle)*(radius+10));ctx.lineTo(Math.cos(angle+.2)*(radius-1),Math.sin(angle+.2)*(radius-1));ctx.fill();}}if(level>=9){ctx.globalAlpha=1;ctx.fillStyle='#ffe36e';ctx.beginPath();ctx.moveTo(-12,-e.r-14);ctx.lineTo(-7,-e.r-25);ctx.lineTo(0,-e.r-16);ctx.lineTo(7,-e.r-25);ctx.lineTo(12,-e.r-14);ctx.closePath();ctx.fill();}ctx.restore();const barY=e.y-e.r-17;ctx.save();ctx.fillStyle=level>=6?'#ffd778':'#b9e9ff';ctx.font='bold 7px system-ui';ctx.textAlign='center';ctx.fillText(`LV ${level}`,e.x,barY-25);ctx.restore(); }
function drawAirstrikeTarget(strike) { const pulse=1+Math.sin(performance.now()/90)*.07;ctx.save();ctx.translate(strike.x,strike.y);ctx.scale(pulse,pulse);ctx.globalAlpha=.85;ctx.strokeStyle='#ffdf6a';ctx.lineWidth=3;ctx.beginPath();ctx.arc(0,0,strike.radius,0,Math.PI*2);ctx.stroke();ctx.strokeStyle='#ff675e';ctx.lineWidth=2;ctx.beginPath();ctx.moveTo(-22,0);ctx.lineTo(22,0);ctx.moveTo(0,-22);ctx.lineTo(0,22);ctx.stroke();ctx.globalAlpha=.25;ctx.fillStyle='#ff9a54';ctx.beginPath();ctx.arc(0,0,strike.radius,0,Math.PI*2);ctx.fill();ctx.restore(); }
function drawBossCutscene() { if(!bossIntro)return; const boss=bossIntro.type, progress=1-bossIntro.time/bossIntro.duration, pulse=1+Math.sin(performance.now()/95)*.05;ctx.save();ctx.fillStyle='#08101ddd';ctx.fillRect(0,0,W,H);ctx.translate(W/2,H/2);ctx.scale(pulse,pulse);ctx.globalAlpha=Math.min(1,progress*4);ctx.fillStyle=boss.body;ctx.beginPath();ctx.arc(0,4,106,0,Math.PI*2);ctx.fill();ctx.fillStyle=boss.top;ctx.beginPath();ctx.arc(0,-38,78,Math.PI,0);ctx.fill();ctx.strokeStyle='#fff1ac';ctx.lineWidth=6;ctx.beginPath();ctx.arc(0,4,112,0,Math.PI*2);ctx.stroke();ctx.fillStyle='#271d2a';ctx.fillRect(-52,-10,22,14);ctx.fillRect(30,-10,22,14);ctx.fillStyle='#ffe36a';ctx.font='900 20px system-ui';ctx.textAlign='center';ctx.fillText('BOSS APPROACHES',0,-156);ctx.fillStyle='#fff4c8';ctx.font='900 32px system-ui';ctx.fillText(boss.name,0,154);ctx.fillStyle='#f8b7a6';ctx.font='bold 14px system-ui';ctx.fillText(`WAVE ${wave} - PREPARE THE DEFENSE`,0,181);ctx.restore(); }
function draw() { ctx.clearRect(0,0,W,H);ctx.fillStyle='#0d2930';ctx.fillRect(0,0,W,H);ctx.save();ctx.translate(W/2,H/2);ctx.scale(camera.zoom,camera.zoom);ctx.translate(-camera.x,-camera.y);drawMap();drawPortal();for(const strike of airstrikes)drawAirstrikeTarget(strike);for(const t of towers)drawPlacedTower(t);for(const e of enemies){drawEnemy(e);drawEnemyLevelEffect(e);}for(const s of shots){ctx.strokeStyle=s.color;ctx.lineWidth=s.kind==='spark'?3:5;ctx.beginPath();ctx.arc(s.x,s.y,s.kind==='spark'?3:5,0,Math.PI*2);ctx.stroke();}for(const p of particles){ctx.globalAlpha=Math.min(1,p.life*3);ctx.fillStyle=p.color;ctx.beginPath();ctx.arc(p.x,p.y,p.burst?(1-p.life)*38:p.size,0,Math.PI*2);ctx.fill();ctx.globalAlpha=1;}ctx.restore();drawBossCutscene(); }
